"""Pure-TTNN NemotronH MoE mixer for `nemotron_h_m_o_e`.

The canonical `TtMoeLayer` (models/tt_transformers/tt/mixtral_moe.py) is
structurally inapplicable to this component:

  * It hard-asserts ``num_devices == 8`` — this is a QB2 2x2 = **4-device**
    mesh.
  * It is a top-2-of-8-expert, Meta-naming (``block_sparse_moe.gate``),
    softmax-gated Mixtral router.  NemotronH MoE is top-**6**-of-**128**,
    HF-naming (``gate.weight`` / ``experts.N.{up,down}_proj``),
    **sigmoid**-gated with an additive ``e_score_correction_bias`` and
    ``relu2`` (relu(x)**2) expert MLPs + a shared expert.
  * Its construction path goes through ``ModelArgs(mesh_device=...)`` which
    cannot load this repo's custom HF code (ValueError: custom code).

So this stub computes the forward with native ``ttnn.*`` ops, mirroring the
graduated `nemotron_h_mamba2_mixer` sibling.  The canonical import is retained
per the ADAPT requirement.

HF reference (modeling_nemotron_h.py NemotronHMOE.forward):

    topk_indices, topk_weights = gate(hidden)          # sigmoid+bias, top-6
    out = moe(hidden, topk_indices, topk_weights)      # sum selected experts
    out = out + shared_experts(hidden)

Router (n_group=1, topk_group=1 → group machinery is a no-op):
    logits = hidden @ gate.weight.T            (fp32)
    scores = sigmoid(logits)
    scores_b = scores + e_score_correction_bias
    select top-6 of scores_b ; weights = scores.gather(top6)
    weights = weights / (sum(weights)+1e-20) * routed_scaling_factor

Implemented densely: every expert is evaluated for all tokens, then weighted
by a (tokens, n_experts) routing matrix that is zero for unselected experts
(mathematically identical to the sparse HF loop).
"""
from __future__ import annotations
import torch
import ttnn

from models.tt_transformers.tt.mixtral_moe import TtMoeLayer  # kept per ADAPT requirement


class TtNemotronHMOE:
    def __init__(self, device, torch_module) -> None:
        self.device = device

        gate = torch_module.gate
        self.top_k = int(gate.top_k)
        self.n_routed_experts = int(gate.n_routed_experts)
        self.routed_scaling_factor = float(gate.routed_scaling_factor)
        self.norm_topk_prob = bool(gate.norm_topk_prob)

        sd = torch_module.state_dict()
        self.hidden_size = sd["gate.weight"].shape[1]

        # ---- router ----
        # gate.weight: (n_experts, hidden) -> store transposed (hidden, n_experts)
        self._gate_w = self._dev(sd["gate.weight"].t().contiguous().float())
        bias = sd.get("gate.e_score_correction_bias", None)
        if bias is None:
            bias = torch.zeros(self.n_routed_experts)
        self._bias = self._dev(bias.float().reshape(1, 1, self.n_routed_experts))

        # ---- routed experts (relu2 MLP, no bias) ----
        self._up = []
        self._down = []
        for e in range(self.n_routed_experts):
            self._up.append(self._devw(sd[f"experts.{e}.up_proj.weight"].t().contiguous()))
            self._down.append(self._devw(sd[f"experts.{e}.down_proj.weight"].t().contiguous()))

        # ---- shared expert ----
        self._sh_up = self._devw(sd["shared_experts.up_proj.weight"].t().contiguous())
        self._sh_down = self._devw(sd["shared_experts.down_proj.weight"].t().contiguous())

        self.ckc = ttnn.WormholeComputeKernelConfig(
            math_fidelity=ttnn.MathFidelity.HiFi4,
            math_approx_mode=False,
            fp32_dest_acc_en=True,
            packer_l1_acc=True,
        )

    # ------------------------------------------------------------------ #
    @classmethod
    def build(cls, device, torch_module):
        return cls(device, torch_module)

    # ----------------------------- helpers ---------------------------- #
    def _is_mesh(self):
        try:
            if isinstance(self.device, ttnn.MeshDevice):
                return True
        except AttributeError:
            pass
        return hasattr(self.device, "get_device_ids") or hasattr(self.device, "get_devices")

    def _upload(self, torch_tensor, dtype, layout=ttnn.TILE_LAYOUT):
        if self._is_mesh():
            try:
                return ttnn.from_torch(
                    torch_tensor, dtype=dtype, layout=layout, device=self.device,
                    mesh_mapper=ttnn.ReplicateTensorToMesh(self.device),
                )
            except Exception:
                pass
        return ttnn.from_torch(torch_tensor, dtype=dtype, layout=layout, device=self.device)

    def _dev(self, torch_tensor, layout=ttnn.TILE_LAYOUT):
        """fp32 constant, mesh-replicated."""
        return self._upload(torch_tensor.float(), ttnn.float32, layout)

    def _devw(self, torch_tensor, layout=ttnn.TILE_LAYOUT):
        """bf16 weight, mesh-replicated (halves DRAM for the 128 experts)."""
        return self._upload(torch_tensor.to(torch.bfloat16), ttnn.bfloat16, layout)

    def _fp32(self, t):
        if isinstance(t, ttnn.Tensor):
            if t.dtype != ttnn.float32:
                return ttnn.typecast(t, ttnn.float32)
            return t
        return self._dev(t)

    # ------------------------------ forward --------------------------- #
    def __call__(self, hidden_states, **kwargs):
        hs = self._fp32(hidden_states)
        if hs.layout != ttnn.TILE_LAYOUT:
            hs = ttnn.to_layout(hs, ttnn.TILE_LAYOUT)
        shape = list(hs.shape)
        B, T = shape[0], shape[1]
        E = self.n_routed_experts

        # ---------------- router (fp32) ----------------
        logits = ttnn.matmul(hs, self._gate_w, compute_kernel_config=self.ckc)  # (B,T,E)
        scores = ttnn.sigmoid(logits)                                           # (B,T,E) fp32
        ttnn.deallocate(logits)
        choice = ttnn.add(scores, self._bias)                                   # selection scores (B,T,E)

        # Top-k selection via a FULLY-FP32 ALL-PAIRS RANK (NOT bf16 ttnn.topk).
        # Measured: bf16 topk's threshold rounds the 6th/7th-of-128 boundary
        # scores equal -> over/under-selects -> PCC caps ~0.979. The rank
        # count is exact in fp32. rank_i = #{j : choice_j > choice_i}; the
        # top_k experts are those with rank < top_k.
        bb = ttnn.reshape(choice, [B, T, 1, E])          # (B,T,1,E): [.,.,0,j]=choice_j
        b_full = ttnn.repeat(bb, [1, 1, E, 1])           # (B,T,E,E): [.,.,i,j]=choice_j
        ttnn.deallocate(bb)
        a_full = ttnn.transpose(b_full, 2, 3)            # (B,T,E,E): [.,.,i,j]=choice_i
        gt = ttnn.gt(b_full, a_full)                      # [.,.,i,j] = choice_j > choice_i
        ttnn.deallocate(b_full)
        ttnn.deallocate(a_full)
        gt_f = ttnn.typecast(gt, ttnn.float32)
        ttnn.deallocate(gt)
        rank = ttnn.sum(gt_f, dim=3)                      # (B,T,E): rank_i = #{j: choice_j>choice_i}
        ttnn.deallocate(gt_f)
        if list(rank.shape)[-1] != E:
            rank = ttnn.reshape(rank, [B, T, E])
        mask = ttnn.lt(rank, float(self.top_k))          # (B,T,E) 1.0/0.0
        ttnn.deallocate(rank)
        ttnn.deallocate(choice)
        if mask.dtype != ttnn.float32:
            mask = ttnn.typecast(mask, ttnn.float32)

        # gather weights from `scores` (NOT choice), normalize over the top-k, scale
        selected = ttnn.multiply(scores, mask)                                 # (B,T,E)
        ttnn.deallocate(scores)
        ttnn.deallocate(mask)
        if self.norm_topk_prob:
            denom = ttnn.sum(selected, dim=-1, keepdim=True)                   # (B,T,1)
            denom = ttnn.add(denom, 1e-20)
            W = ttnn.multiply(selected, ttnn.reciprocal(denom))
            ttnn.deallocate(selected)
            ttnn.deallocate(denom)
        else:
            W = selected
        W = ttnn.multiply(W, self.routed_scaling_factor)                       # (B,T,E) fp32

        # ---------------- experts (dense, fp32-accumulated mixture) ----------------
        # HF sums the top-k weighted expert outputs in fp32 (topk_weights.dtype),
        # so accumulate in fp32; bf16 expert weights/matmuls with HiFi4 fp32 acc.
        hs_bf = ttnn.typecast(hs, ttnn.bfloat16)
        out = None
        for e in range(E):
            up = ttnn.matmul(hs_bf, self._up[e], compute_kernel_config=self.ckc)  # (B,T,inter) bf16
            act = ttnn.relu(up)
            ttnn.deallocate(up)
            act = ttnn.multiply(act, act)                                          # relu2
            down = ttnn.matmul(act, self._down[e], compute_kernel_config=self.ckc)  # (B,T,hidden) bf16
            ttnn.deallocate(act)
            down_f = ttnn.typecast(down, ttnn.float32)
            ttnn.deallocate(down)
            we = ttnn.slice(W, [0, 0, e], [B, T, e + 1])                          # (B,T,1) fp32
            contrib = ttnn.multiply(down_f, we, memory_config=ttnn.DRAM_MEMORY_CONFIG)
            ttnn.deallocate(down_f)
            ttnn.deallocate(we)
            if out is None:
                out = contrib
            else:
                out = ttnn.add(out, contrib, memory_config=ttnn.DRAM_MEMORY_CONFIG)
                ttnn.deallocate(contrib)
        ttnn.deallocate(W)

        # ---------------- shared expert (fp32) ----------------
        s_up = ttnn.matmul(hs_bf, self._sh_up, compute_kernel_config=self.ckc)
        s_act = ttnn.relu(s_up)
        ttnn.deallocate(s_up)
        s_act = ttnn.multiply(s_act, s_act)
        s_down = ttnn.matmul(s_act, self._sh_down, compute_kernel_config=self.ckc)
        ttnn.deallocate(s_act)
        ttnn.deallocate(hs_bf)
        s_down_f = ttnn.typecast(s_down, ttnn.float32)
        ttnn.deallocate(s_down)

        out = ttnn.add(out, s_down_f)                                           # (B,T,hidden) fp32
        ttnn.deallocate(s_down_f)
        return out


# Module-level `build` — primary test entry point.
def build(device, torch_module=None):
    return TtNemotronHMOE.build(device, torch_module)


# Backward-compat module-level shim with the component's lowercase slug name.
def nemotron_h_m_o_e(device, torch_module=None):
    return TtNemotronHMOE.build(device, torch_module)
